const audioText = (() => {
  try {
    const t = $('Transcribe a recording').first()?.json?.text;
    return (typeof t === 'string' && t.trim()) ? t.trim() : '';
  } catch { return ''; }
})();

const manual = (() => {
  try {
    return $('Poczekaj na wszystkie źródła').first().json.body
        || $('Webhook').first().json.body
        || {};
  } catch { return {}; }
})();

function parseVision(nodeName) {
  try {
    // Próbuj różnych ścieżek dostępu
    const item = $(nodeName).first().json;

    const raw = item?.content?.[0]?.text           // bezpośrednio { content: [...] }
             || item?.[0]?.content?.[0]?.text       // jedna tablica [{ content: [...] }]
             || item?.choices?.[0]?.message?.content
             || '';

    if (!raw) return {};
    const clean = raw.replace(/```json\s*/gi,'').replace(/```/g,'').trim();
    return JSON.parse(clean);
  } catch { return {}; }
}

const front = parseVision('Vision – przód wizytówki');
const back  = parseVision('Vision – tył wizytówki');

function first(...vals) {
  return vals.find(v => v !== null && v !== undefined && v !== '') ?? null;
}

const notes = [manual.notes, audioText]
  .filter(v => v && v.trim())
  .join(' ') || null;

const card_extra = [front.card_extra, back.card_extra]
  .filter(v => v && v.trim()).join('; ') || null;

const card = {
  name:     first(manual.name,     front.card_name,     back.card_name),
  company:  first(manual.company,  front.card_company,  back.card_company),
  email:    first(manual.email,    front.card_email,    back.card_email),
  phone:    first(manual.phone,    front.card_phone,    back.card_phone),
  position: first(manual.position, front.card_position, back.card_position),
  notes,
  extra:    card_extra
};

const hasData = card.name || card.email || card.phone || card.company || card.notes;

if (!hasData) {
  throw new Error('Brak danych: nie przesłano formularza, wizytówki ani nagrania.');
}

return [{
  json: card
}];

// Parsuj odpowiedź GPT do czystego JSON
const raw = $input.first().json.output?.[0]?.content?.[0]?.text
         || $input.first().json.choices?.[0]?.message?.content
         || '';

let parsed;
try {
  const clean = raw.replace(/```json\s*/gi,'').replace(/```/g,'').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { _parse_error: raw };
}

// Walidacja minimum
if (!parsed.name && !parsed.email && !parsed.phone) {
  parsed._warning = 'Brak podstawowych danych kontaktowych';
}

return [{ json: parsed }];

// Parsuj odpowiedź GPT z polami podatkowymi
const raw = $input.first().json.output?.[0]?.content?.[0]?.text
         || $input.first().json.choices?.[0]?.message?.content
         || '';

let parsed;
try {
  const clean = raw.replace(/```json\s*/gi,'').replace(/```/g,'').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { contact_tax_fields: {}, deal_tax_fields: {}, _parse_error: raw };
}

return [{ json: parsed }];

