// Połącz dane kontaktowe z polami podatkowymi
const contact = $('Parse + waliduj JSON').first().json;
const tax     = $('Parse pola podatkowe').first().json;

const nip    = contact.nip    || tax.contact_tax_fields?.nip    || null;
const regon  = contact.regon  || tax.contact_tax_fields?.regon  || null;
const krs    = contact.krs    || tax.contact_tax_fields?.krs    || null;

return [{
  json: {
    ...contact,
    nip, regon, krs,
    contact_tax_fields: tax.contact_tax_fields ?? {},
    deal_tax_fields:    tax.deal_tax_fields    ?? {}
  }
}];

const d = $input.first().json;
const orgName = (d.company && d.company.trim()) ? d.company.trim() : (d.name ? d.name.trim() : null);
return [{ json: { ...d, _orgName: orgName } }];
